9	// Hold the splash screen until custom fonts register вҖ” text with an unregistered
10	// fontFamily silently falls back to System on iOS and the swap is visible to the user.
11	SplashScreen.preventAutoHideAsync();
12	
13	export default function RootLayout() {
14	  const [fontsLoaded, fontError] = useFonts(fontAssets);
15	
16	  useEffect(() => {
17	    if (fontsLoaded || fontError) {
18	      SplashScreen.hideAsync();
19	    }
20	  }, [fontsLoaded, fontError]);
21	
22	  if (!fontsLoaded && !fontError) {
23	    return null;
24	  }
25	
26	  return (
27	    <GestureHandlerRootView style={{ flex: 1 }}>
28	      <Slot />
29	      <StatusBar style="auto" />
30	    </GestureHandlerRootView>
31	  );
32	}
